<?php/*入力フォーム文字からプレビュー表示用タグに変換第1引数：変換対象変数第2引数：エンコード文字コード第3引数：改行処理の有無（0：無、1：有）*///入力フォーム文字からHTMLタグに変換function change_html($str,$charcode,$br) {	//半角カナを全角カナに変換、全角英数を半角英数に変換	$str = mb_convert_kana($str, "KV",$charcode);	$str = mb_convert_kana($str, "as",$charcode);	//タグを無効化	$str = htmlspecialchars($str);	//改行処理	if ($br > 0) {		$str = nl2br($str);	}	return($str);}//HTMLタグから入力フォーム文字に変換function re_change_html($str,$br) {	//改行処理	if ($br > 0) {		$str = str_replace("<br />","",$str);		$str = str_replace("<br>","",$str);	}	return($str);}?>